features.snippet:
reg [3:0] control_r;
reg parity_rec_c;
always @(posedge ready_control or negedge rx_resetn) begin
  if (!rx_resetn) begin
    control_r    <= 4'd0;
    parity_rec_c <= 1'b0;
  end else begin
    control_r    <= {bit_c_3, bit_c_2, bit_c_1, bit_c_0};
    parity_rec_c <= bit_c_3;
  end
end

reg [3:0] packed_out;
reg single_bit_out;
always @(posedge clk or negedge rstn) begin
  if (!rstn) begin
    packed_out    <= 4'd0;
    single_bit_out <= 1'b0;
  end else begin
    packed_out    <= {sig3, sig2, sig1, sig0};
    single_bit_out <= sig3;
  end
end

reg bit_c_3, bit_c_2, bit_c_1, bit_c_0;
reg [3:0] control_r;
always @(posedge clk) begin
  control_r <= {bit_c_3, bit_c_2, bit_c_1, bit_c_0};
end

reg parity_gen;
reg [7:0] data;
reg [1:0] control;
reg last_is_control, last_is_data;
always @(posedge clk) begin
  if (last_is_control)
    parity_gen <= !(bit2 ^ control[0] ^ control[1]);
  else if (last_is_data)
    parity_gen <= !(bit2 ^ data[7] ^ data[6] ^ data[5] ^ data[4] ^
                   data[3] ^ data[2] ^ data[1] ^ data[0]);
end
